#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, V; scanf("%lld %lld", &N, &V);
        long long M = N - 1; // moves
        long long maxCost = M * (M + 1) / 2;
        long long minCost;
        if (M <= V) {
            minCost = M;
        } else {
            long long L = N - V; // L >= 2
            minCost = V + (L * (L + 1) / 2) - 1;
        }
        printf("%lld %lld\n", maxCost, minCost);
    }
    return 0;
}

