            long maxCost = M * (M + 1) / 2;
            long minCost;
            if (M <= V) {
                minCost = M;
            } else {
                long L = N - V; // = M - V + 1
                minCost = V + (L * (L + 1) / 2) - 1;
            }
            sb.append(maxCost).append(' ').append(minCost).append('\n');
        }
        System.out.print(sb.toString());
