#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); V = int(next(it))
        M = N - 1
        max_cost = M * (M + 1) // 2
        if M <= V:
            min_cost = M
        else:
            L = N - V  # = M - V + 1
            min_cost = V + (L * (L + 1) // 2) - 1
        out.append(f"{max_cost} {min_cost}")
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

